import flask
import prometheus_client
import time

app = flask.Flask(__name__)

# Prometheus Metrics
# Counter for total requests
REQUEST_COUNT = prometheus_client.Counter(
    'http_requests_total',
    'Total HTTP Requests',
    ['method', 'endpoint', 'status_code']
)

# Histogram for request durations
REQUEST_LATENCY = prometheus_client.Histogram(
    'http_request_duration_seconds',
    'HTTP Request Latency',
    ['method', 'endpoint']
)

# Summary for detailed API usage (specific to requirements)
# Note: Using Summary for potentially high-cardinality labels, but consider impact on Prometheus server
# For very high cardinality (e.g., unique request bodies per request), this might not be scalable.
# A better approach for bodies might be logging or a separate system, or aggregating/hashing the body.
# For demonstration, we'll include it.
API_USAGE_DETAILED = prometheus_client.Summary(
    'api_usage_detailed_requests_total',
    'Detailed API Usage Metrics',
    ['user_id', 'api_key', 'method', 'endpoint', 'request_body_hash'] # Hashing body to avoid extremely long labels
)

# In-progress requests gauge (optional but good practice)
IN_PROGRESS_REQUESTS = prometheus_client.Gauge(
    'http_requests_in_progress',
    'Number of in-progress requests',
    ['method', 'endpoint']
)


def get_user_id(request):
    """Placeholder to extract user ID from request (e.g., header, query param, JWT)."""
    return request.headers.get('X-User-ID', 'anonymous')

def get_api_key(request):
    """Placeholder to extract API Key from request (e.g., header, query param)."""
    return request.headers.get('X-API-Key', 'N/A')

def hash_request_body(request):
    """Hashes the request body for use in Prometheus labels.
    Avoids putting entire potentially large/sensitive bodies into labels directly.
    """
    if request.method in ['POST', 'PUT', 'PATCH'] and request.data:
        import hashlib
        return hashlib.md5(request.data).hexdigest()
    return 'N/A'


@app.before_request
def before_request_hook():
    endpoint = flask.request.endpoint if flask.request.endpoint else 'unknown'
    method = flask.request.method
    IN_PROGRESS_REQUESTS.labels(method=method, endpoint=endpoint).inc()
    flask.g.start_time = time.time() # Store start time for latency calculation


@app.after_request
def after_request_hook(response):
    endpoint = flask.request.endpoint if flask.request.endpoint else 'unknown'
    method = flask.request.method
    status_code = response.status_code

    # Increment request counter
    REQUEST_COUNT.labels(method=method, endpoint=endpoint, status_code=status_code).inc()

    # Observe request latency
    if hasattr(flask.g, 'start_time'):
        request_latency = time.time() - flask.g.start_time
        REQUEST_LATENCY.labels(method=method, endpoint=endpoint).observe(request_latency)

    # Decrement in-progress requests
    IN_PROGRESS_REQUESTS.labels(method=method, endpoint=endpoint).dec()

    # Detailed API Usage Metrics
    if endpoint not in ['metrics', 'static']: # Exclude metrics and static files from detailed usage
        user_id = get_user_id(flask.request)
        api_key = get_api_key(flask.request)
        request_body_hash = hash_request_body(flask.request)

        API_USAGE_DETAILED.labels(
            user_id=user_id,
            api_key=api_key,
            method=method,
            endpoint=endpoint,
            request_body_hash=request_body_hash
        ).observe(1) # Observe '1' as a count of this specific detailed usage event

    return response


@app.route('/')
def home():
    return 'Welcome to the API! Try /hello or /submit.'

@app.route('/hello')
def hello_world():
    user_id = get_user_id(flask.request)
    return f'Hello, {user_id}!'

@app.route('/submit', methods=['POST'])
def submit_data():
    data = flask.request.get_json(silent=True)
    if not data:
        return flask.jsonify({'message': 'Invalid JSON data'}), 400
    return flask.jsonify({'received': data, 'message': 'Data submitted successfully!'}), 200

@app.route('/slow_endpoint')
def slow_endpoint():
    time.sleep(0.5) # Simulate work
    return 'This was a slow request!'

@app.route('/error')
def simulate_error():
    raise Exception("Simulated internal server error")

# Error handler to ensure metrics are recorded even on internal errors
@app.errorhandler(Exception)
def handle_exception(e):
    # Log the error if necessary
    app.logger.error(f"An error occurred: {e}", exc_info=True)

    # Increment request counter for 500 status
    endpoint = flask.request.endpoint if flask.request.endpoint else 'unknown'
    method = flask.request.method
    status_code = 500 # Internal Server Error

    REQUEST_COUNT.labels(method=method, endpoint=endpoint, status_code=status_code).inc()

    # Observe request latency (if start_time exists)
    if hasattr(flask.g, 'start_time'):
        request_latency = time.time() - flask.g.start_time
        REQUEST_LATENCY.labels(method=method, endpoint=endpoint).observe(request_latency)

    # Decrement in-progress requests
    IN_PROGRESS_REQUESTS.labels(method=method, endpoint=endpoint).dec()

    # Return a generic error response
    return flask.jsonify({'message': 'Internal Server Error'}), 500


@app.route('/metrics')
def metrics():
    return flask.Response(prometheus_client.generate_latest(), mimetype='text/plain')

if __name__ == '__main__':
    # Start up the server to expose the metrics.
    # We are using Flask's built-in server for simplicity,
    # but in production, use a WSGI server like Gunicorn.
    # Also, consider running prometheus_client.start_http_server(PORT)
    # in a separate thread/process if you need to decouple it from the main app.
    # For a Flask app, exposing /metrics directly is common.
    app.run(host='0.0.0.0', port=5000)